178	
179	static void
180	ngx_http_v3_init_request_stream(ngx_connection_t *c)
181	{
182	    uint64_t                   n;
183	    ngx_event_t               *rev;
184	    ngx_pool_cleanup_t        *cln;
185	    ngx_http_connection_t     *hc;
186	    ngx_http_v3_session_t     *h3c;
187	    ngx_http_core_loc_conf_t  *clcf;
188	    ngx_http_core_srv_conf_t  *cscf;
189	
190	    ngx_log_debug0(NGX_LOG_DEBUG_HTTP, c->log, 0, "http3 init request stream");
191	
192	#if (NGX_STAT_STUB)
193	    (void) ngx_atomic_fetch_add(ngx_stat_active, 1);
194	#endif
195	
196	    hc = c->data;
197	
198	    clcf = ngx_http_get_module_loc_conf(hc->conf_ctx, ngx_http_core_module);
199	
200	    n = c->quic->id >> 2;
201	
202	    if (n >= clcf->keepalive_requests * 2) {
203	        ngx_http_v3_finalize_connection(c, NGX_HTTP_V3_ERR_EXCESSIVE_LOAD,
204	                                        "too many requests per connection");
205	        ngx_http_close_connection(c);
206	        return;
207	    }
208	
209	    h3c = ngx_http_v3_get_session(c);
210	
211	    if (h3c->goaway) {
212	        c->close = 1;
213	        ngx_http_close_connection(c);
214	        return;
215	    }
216	
217	    h3c->next_request_id = c->quic->id + 0x04;
218	
219	    if (n + 1 == clcf->keepalive_requests
220	        || ngx_current_msec - c->start_time > clcf->keepalive_time)
221	    {
222	        h3c->goaway = 1;
223	
224	        if (!h3c->hq) {
225	            if (ngx_http_v3_send_goaway(c, h3c->next_request_id) != NGX_OK) {
226	                ngx_http_close_connection(c);
227	                return;
228	            }
229	        }
230	
231	        ngx_http_v3_shutdown_connection(c, NGX_HTTP_V3_ERR_NO_ERROR,
232	                                        "reached maximum number of requests");
233	    }
234	
235	    cln = ngx_pool_cleanup_add(c->pool, 0);
236	    if (cln == NULL) {
237	        ngx_http_close_connection(c);
238	        return;
239	    }
240	
241	    cln->handler = ngx_http_v3_cleanup_connection;
242	    cln->data = c;
243	
244	    h3c->nrequests++;
245	
246	    if (h3c->keepalive.timer_set) {
247	        ngx_del_timer(&h3c->keepalive);
248	    }
249	
250	    rev = c->read;
251	
252	    if (!h3c->hq) {
253	        rev->handler = ngx_http_v3_wait_request_handler;
254	        c->write->handler = ngx_http_empty_handler;
255	    }
256	
257	    if (rev->ready) {
258	        rev->handler(rev);
259	        return;
260	    }
261	
262	    cscf = ngx_http_get_module_srv_conf(hc->conf_ctx, ngx_http_core_module);
263	
264	    ngx_add_timer(rev, cscf->client_header_timeout);
265	    ngx_reusable_connection(c, 1);
266	
267	    if (ngx_handle_read_event(rev, 0) != NGX_OK) {
268	        ngx_http_close_connection(c);
269	        return;
270	    }
271	}
272	
273	
274	static void
275	ngx_http_v3_wait_request_handler(ngx_event_t *rev)
276	{
277	    size_t                     size;
278	    ssize_t                    n;
279	    ngx_buf_t                 *b;
280	    ngx_connection_t          *c;
281	    ngx_pool_cleanup_t        *cln;
282	    ngx_http_request_t        *r;
283	    ngx_http_connection_t     *hc;
284	    ngx_http_core_srv_conf_t  *cscf;
285	
286	    c = rev->data;
287	
288	    ngx_log_debug0(NGX_LOG_DEBUG_HTTP, c->log, 0, "http3 wait request handler");
289	
290	    if (rev->timedout) {
291	        ngx_log_error(NGX_LOG_INFO, c->log, NGX_ETIMEDOUT, "client timed out");
292	        c->timedout = 1;
293	        ngx_http_close_connection(c);
294	        return;
295	    }
296	
297	    if (c->close) {
298	        ngx_http_close_connection(c);
299	        return;
300	    }
301	
302	    hc = c->data;
303	    cscf = ngx_http_get_module_srv_conf(hc->conf_ctx, ngx_http_core_module);
304	
305	    size = cscf->client_header_buffer_size;
306	
307	    b = c->buffer;
308	
309	    if (b == NULL) {
310	        b = ngx_create_temp_buf(c->pool, size);
311	        if (b == NULL) {
312	            ngx_http_close_connection(c);
313	            return;
314	        }
315	
316	        c->buffer = b;
317	
318	    } else if (b->start == NULL) {
319	
320	        b->start = ngx_palloc(c->pool, size);
321	        if (b->start == NULL) {
322	            ngx_http_close_connection(c);
323	            return;
324	        }
325	
326	        b->pos = b->start;
327	        b->last = b->start;
328	        b->end = b->last + size;
329	    }
330	
331	    n = c->recv(c, b->last, size);
332	
333	    if (n == NGX_AGAIN) {
334	
335	        if (!rev->timer_set) {
336	            ngx_add_timer(rev, cscf->client_header_timeout);
337	            ngx_reusable_connection(c, 1);
338	        }
339	
340	        if (ngx_handle_read_event(rev, 0) != NGX_OK) {
341	            ngx_http_close_connection(c);
342	            return;
343	        }
344	
345	        /*
346	         * We are trying to not hold c->buffer's memory for an idle connection.
347	         */
348	
349	        if (ngx_pfree(c->pool, b->start) == NGX_OK) {
350	            b->start = NULL;
351	        }
352	
353	        return;
354	    }
355	
356	    if (n == NGX_ERROR) {
357	        ngx_http_close_connection(c);
358	        return;
359	    }
360	
361	    if (n == 0) {
362	        ngx_log_error(NGX_LOG_INFO, c->log, 0,
363	                      "client closed connection");
364	        ngx_http_close_connection(c);
365	        return;
366	    }
367	
368	    b->last += n;
369	
370	    c->log->action = "reading client request";
371	
372	    ngx_reusable_connection(c, 0);
373	
374	    r = ngx_http_create_request(c);
375	    if (r == NULL) {
376	        ngx_http_close_connection(c);
377	        return;
378	    }
379	
380	    r->http_version = NGX_HTTP_VERSION_30;
381	
382	    r->v3_parse = ngx_pcalloc(r->pool, sizeof(ngx_http_v3_parse_t));
383	    if (r->v3_parse == NULL) {
384	        ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
385	        return;
386	    }
387	
388	    r->v3_parse->header_limit = cscf->large_client_header_buffers.size
389	                                * cscf->large_client_header_buffers.num;
390	
391	    c->data = r;
392	    c->requests = (c->quic->id >> 2) + 1;
393	
394	    cln = ngx_pool_cleanup_add(r->pool, 0);
395	    if (cln == NULL) {
396	        ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
397	        return;
398	    }
399	
400	    cln->handler = ngx_http_v3_cleanup_request;
401	    cln->data = r;
402	
403	    rev->handler = ngx_http_v3_process_request;
404	    ngx_http_v3_process_request(rev);
405	}
