408	void
409	ngx_http_v3_reset_stream(ngx_connection_t *c)
410	{
411	    ngx_http_v3_session_t  *h3c;
412	
413	    h3c = ngx_http_v3_get_session(c);
414	
415	    if (!c->read->eof && !h3c->hq
416	        && h3c->known_streams[NGX_HTTP_V3_STREAM_SERVER_DECODER]
417	        && (c->quic->id & NGX_QUIC_STREAM_UNIDIRECTIONAL) == 0)
418	    {
419	        (void) ngx_http_v3_send_cancel_stream(c, c->quic->id);
420	    }
421	
422	    if (c->timedout) {
423	        ngx_quic_reset_stream(c, NGX_HTTP_V3_ERR_GENERAL_PROTOCOL_ERROR);
424	
425	    } else if (c->close) {
426	        ngx_quic_reset_stream(c, NGX_HTTP_V3_ERR_REQUEST_REJECTED);
427	
428	    } else if (c->requests == 0 || c->error) {
429	        ngx_quic_reset_stream(c, NGX_HTTP_V3_ERR_INTERNAL_ERROR);
430	    }
431	}
