434	static void
435	ngx_http_v3_cleanup_connection(void *data)
436	{
437	    ngx_connection_t  *c = data;
438	
439	    ngx_http_v3_session_t     *h3c;
440	    ngx_http_core_loc_conf_t  *clcf;
441	
442	    h3c = ngx_http_v3_get_session(c);
443	
444	    if (--h3c->nrequests == 0) {
445	        clcf = ngx_http_v3_get_module_loc_conf(c, ngx_http_core_module);
446	        ngx_add_timer(&h3c->keepalive, clcf->keepalive_timeout);
447	    }
448	}
