461	
462	static void
463	ngx_http_v3_process_request(ngx_event_t *rev)
464	{
465	    u_char                       *p;
466	    ssize_t                       n;
467	    ngx_buf_t                    *b;
468	    ngx_int_t                     rc;
469	    ngx_connection_t             *c;
470	    ngx_http_request_t           *r;
471	    ngx_http_v3_session_t        *h3c;
472	    ngx_http_core_srv_conf_t     *cscf;
473	    ngx_http_v3_parse_headers_t  *st;
474	
475	    c = rev->data;
476	    r = c->data;
477	
478	    ngx_log_debug0(NGX_LOG_DEBUG_HTTP, rev->log, 0, "http3 process request");
479	
480	    if (rev->timedout) {
481	        ngx_log_error(NGX_LOG_INFO, c->log, NGX_ETIMEDOUT, "client timed out");
482	        c->timedout = 1;
483	        ngx_http_close_request(r, NGX_HTTP_REQUEST_TIME_OUT);
484	        return;
485	    }
486	
487	    h3c = ngx_http_v3_get_session(c);
488	
489	    st = &r->v3_parse->headers;
490	
491	    b = r->header_in;
492	
493	    for ( ;; ) {
494	
495	        if (b->pos == b->last) {
496	
497	            if (rev->ready) {
498	                n = c->recv(c, b->start, b->end - b->start);
499	
500	            } else {
501	                n = NGX_AGAIN;
502	            }
503	
504	            if (n == NGX_AGAIN) {
505	                if (!rev->timer_set) {
506	                    cscf = ngx_http_get_module_srv_conf(r,
507	                                                        ngx_http_core_module);
508	                    ngx_add_timer(rev, cscf->client_header_timeout);
509	                }
510	
511	                if (ngx_handle_read_event(rev, 0) != NGX_OK) {
512	                    ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
513	                }
514	
515	                break;
516	            }
517	
518	            if (n == 0) {
519	                ngx_log_error(NGX_LOG_INFO, c->log, 0,
520	                              "client prematurely closed connection");
521	            }
522	
523	            if (n == 0 || n == NGX_ERROR) {
524	                c->error = 1;
525	                c->log->action = "reading client request";
526	
527	                ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
528	                break;
529	            }
530	
531	            b->pos = b->start;
532	            b->last = b->start + n;
533	        }
534	
535	        p = b->pos;
536	
537	        rc = ngx_http_v3_parse_headers(c, st, b);
538	
539	        if (rc > 0) {
540	            ngx_quic_reset_stream(c, rc);
541	            ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
542	                          "client sent invalid header");
543	            ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
544	            break;
545	        }
546	
547	        if (rc == NGX_ERROR) {
548	            ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
549	            break;
550	        }
551	
552	        r->request_length += b->pos - p;
553	        h3c->total_bytes += b->pos - p;
554	
555	        if (ngx_http_v3_check_flood(c) != NGX_OK) {
556	            ngx_http_close_request(r, NGX_HTTP_CLOSE);
557	            break;
558	        }
559	
560	        if (rc == NGX_BUSY) {
561	            if (rev->error) {
562	                ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
563	                break;
564	            }
565	
566	            if (!rev->timer_set) {
567	                cscf = ngx_http_get_module_srv_conf(r,
568	                                                    ngx_http_core_module);
569	                ngx_add_timer(rev, cscf->client_header_timeout);
570	            }
571	
572	            if (ngx_handle_read_event(rev, 0) != NGX_OK) {
573	                ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
574	            }
575	
576	            break;
577	        }
578	
579	        if (rc == NGX_AGAIN) {
580	            continue;
581	        }
582	
583	        /* rc == NGX_OK || rc == NGX_DONE */
584	
585	        h3c->payload_bytes += ngx_http_v3_encode_field_l(NULL,
586	                                                   &st->field_rep.field.name,
587	                                                   &st->field_rep.field.value);
588	
589	        if (ngx_http_v3_process_header(r, &st->field_rep.field.name,
590	                                       &st->field_rep.field.value)
591	            != NGX_OK)
592	        {
593	            break;
594	        }
595	
596	        if (rc == NGX_DONE) {
597	            if (ngx_http_v3_process_request_header(r) != NGX_OK) {
598	                break;
599	            }
600	
601	            ngx_http_process_request(r);
602	            break;
603	        }
604	    }
605	
606	    ngx_http_run_posted_requests(c);
607	
608	    return;
609	}
610	
611	
612	static ngx_int_t
613	ngx_http_v3_process_header(ngx_http_request_t *r, ngx_str_t *name,
614	    ngx_str_t *value)
615	{
616	    size_t                      len;
617	    ngx_table_elt_t            *h;
618	    ngx_http_header_t          *hh;
619	    ngx_http_core_srv_conf_t   *cscf;
620	    ngx_http_core_main_conf_t  *cmcf;
621	
622	    static ngx_str_t cookie = ngx_string("cookie");
623	
624	    len = name->len + value->len;
625	
626	    if (len > r->v3_parse->header_limit) {
627	        ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
628	                      "client sent too large header");
629	        ngx_http_finalize_request(r, NGX_HTTP_REQUEST_HEADER_TOO_LARGE);
630	        return NGX_ERROR;
631	    }
632	
633	    r->v3_parse->header_limit -= len;
634	
635	    if (ngx_http_v3_validate_header(r, name, value) != NGX_OK) {
636	        ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
637	        return NGX_ERROR;
638	    }
639	
640	    if (r->invalid_header) {
641	        cscf = ngx_http_get_module_srv_conf(r, ngx_http_core_module);
642	
643	        if (cscf->ignore_invalid_headers) {
644	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
645	                          "client sent invalid header: \"%V\"", name);
646	
647	            return NGX_OK;
648	        }
649	    }
650	
651	    if (name->len && name->data[0] == ':') {
652	        return ngx_http_v3_process_pseudo_header(r, name, value);
653	    }
654	
655	    if (ngx_http_v3_init_pseudo_headers(r) != NGX_OK) {
656	        return NGX_ERROR;
657	    }
658	
659	    if (name->len == cookie.len
660	        && ngx_memcmp(name->data, cookie.data, cookie.len) == 0)
661	    {
662	        if (ngx_http_v3_cookie(r, value) != NGX_OK) {
663	            ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
664	            return NGX_ERROR;
665	        }
666	
667	    } else {
668	        cscf = ngx_http_get_module_srv_conf(r, ngx_http_core_module);
669	
670	        if (r->headers_in.count++ >= cscf->max_headers) {
671	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
672	                          "client sent too many header lines");
673	            ngx_http_finalize_request(r, NGX_HTTP_REQUEST_HEADER_TOO_LARGE);
674	            return NGX_ERROR;
675	        }
676	
677	        h = ngx_list_push(&r->headers_in.headers);
678	        if (h == NULL) {
679	            ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
680	            return NGX_ERROR;
681	        }
682	
683	        h->key = *name;
684	        h->value = *value;
685	        h->lowcase_key = h->key.data;
686	        h->hash = ngx_hash_key(h->key.data, h->key.len);
687	
688	        cmcf = ngx_http_get_module_main_conf(r, ngx_http_core_module);
689	
690	        hh = ngx_hash_find(&cmcf->headers_in_hash, h->hash,
691	                           h->lowcase_key, h->key.len);
692	
693	        if (hh && hh->handler(r, h, hh->offset) != NGX_OK) {
694	            return NGX_ERROR;
695	        }
696	    }
697	
698	    ngx_log_debug2(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
699	                   "http3 header: \"%V: %V\"", name, value);
700	    return NGX_OK;
701	}
702	
703	
704	static ngx_int_t
705	ngx_http_v3_validate_header(ngx_http_request_t *r, ngx_str_t *name,
706	    ngx_str_t *value)
707	{
708	    u_char                     ch;
709	    ngx_uint_t                 i;
710	    ngx_http_core_srv_conf_t  *cscf;
711	
712	    r->invalid_header = 0;
713	
714	    cscf = ngx_http_get_module_srv_conf(r, ngx_http_core_module);
715	
716	    for (i = (name->data[0] == ':'); i != name->len; i++) {
717	        ch = name->data[i];
718	
719	        if ((ch >= 'a' && ch <= 'z')
720	            || (ch == '-')
721	            || (ch >= '0' && ch <= '9')
722	            || (ch == '_' && cscf->underscores_in_headers))
723	        {
724	            continue;
725	        }
726	
727	        if (ch <= 0x20 || ch == 0x7f || ch == ':'
728	            || (ch >= 'A' && ch <= 'Z'))
729	        {
730	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
731	                          "client sent invalid header name: \"%V\"", name);
732	
733	            return NGX_ERROR;
734	        }
735	
736	        r->invalid_header = 1;
737	    }
738	
739	    for (i = 0; i != value->len; i++) {
740	        ch = value->data[i];
741	
742	        if (ch == '\0' || ch == LF || ch == CR) {
743	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
744	                          "client sent header \"%V\" with "
745	                          "invalid value: \"%V\"", name, value);
746	
747	            return NGX_ERROR;
748	        }
749	    }
750	
751	    return NGX_OK;
752	}
