754	
755	static ngx_int_t
756	ngx_http_v3_process_pseudo_header(ngx_http_request_t *r, ngx_str_t *name,
757	    ngx_str_t *value)
758	{
759	    u_char      ch, c;
760	    ngx_uint_t  i;
761	
762	    if (r->request_line.len) {
763	        ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
764	                      "client sent out of order pseudo-headers");
765	        goto failed;
766	    }
767	
768	    if (name->len == 7 && ngx_strncmp(name->data, ":method", 7) == 0) {
769	
770	        if (r->method_name.len) {
771	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
772	                          "client sent duplicate \":method\" header");
773	            goto failed;
774	        }
775	
776	        if (value->len == 0) {
777	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
778	                          "client sent empty \":method\" header");
779	            goto failed;
780	        }
781	
782	        r->method_name = *value;
783	
784	        for (i = 0; i < sizeof(ngx_http_v3_methods)
785	                        / sizeof(ngx_http_v3_methods[0]); i++)
786	        {
787	            if (value->len == ngx_http_v3_methods[i].name.len
788	                && ngx_strncmp(value->data,
789	                               ngx_http_v3_methods[i].name.data, value->len)
790	                   == 0)
791	            {
792	                r->method = ngx_http_v3_methods[i].method;
793	                break;
794	            }
795	        }
796	
797	        for (i = 0; i < value->len; i++) {
798	            ch = value->data[i];
799	
800	            if ((ch < 'A' || ch > 'Z') && ch != '_' && ch != '-') {
801	                ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
802	                              "client sent invalid method: \"%V\"", value);
803	                goto failed;
804	            }
805	        }
806	
807	        ngx_log_debug2(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
808	                       "http3 method \"%V\" %ui", value, r->method);
809	        return NGX_OK;
810	    }
811	
812	    if (name->len == 5 && ngx_strncmp(name->data, ":path", 5) == 0) {
813	
814	        if (r->uri_start) {
815	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
816	                          "client sent duplicate \":path\" header");
817	            goto failed;
818	        }
819	
820	        if (value->len == 0) {
821	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
822	                          "client sent empty \":path\" header");
823	            goto failed;
824	        }
825	
826	        r->uri_start = value->data;
827	        r->uri_end = value->data + value->len;
828	
829	        if (ngx_http_parse_uri(r) != NGX_OK) {
830	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
831	                          "client sent invalid \":path\" header: \"%V\"",
832	                          value);
833	            goto failed;
834	        }
835	
836	        ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
837	                       "http3 path \"%V\"", value);
838	        return NGX_OK;
839	    }
840	
841	    if (name->len == 7 && ngx_strncmp(name->data, ":scheme", 7) == 0) {
842	
843	        if (r->schema.len) {
844	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
845	                          "client sent duplicate \":scheme\" header");
846	            goto failed;
847	        }
848	
849	        if (value->len == 0) {
850	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
851	                          "client sent empty \":scheme\" header");
852	            goto failed;
853	        }
854	
855	        for (i = 0; i < value->len; i++) {
856	            ch = value->data[i];
857	
858	            c = (u_char) (ch | 0x20);
859	            if (c >= 'a' && c <= 'z') {
860	                continue;
861	            }
862	
863	            if (((ch >= '0' && ch <= '9')
864	                 || ch == '+' || ch == '-' || ch == '.')
865	                && i > 0)
866	            {
867	                continue;
868	            }
869	
870	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
871	                          "client sent invalid \":scheme\" header: \"%V\"",
872	                          value);
873	            goto failed;
874	        }
875	
876	        r->schema = *value;
877	
878	        ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
879	                       "http3 schema \"%V\"", value);
880	        return NGX_OK;
881	    }
882	
883	    if (name->len == 10 && ngx_strncmp(name->data, ":authority", 10) == 0) {
884	
885	        if (r->host_start) {
886	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
887	                          "client sent duplicate \":authority\" header");
888	            goto failed;
889	        }
890	
891	        r->host_start = value->data;
892	        r->host_end = value->data + value->len;
893	
894	        ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
895	                       "http3 authority \"%V\"", value);
896	        return NGX_OK;
897	    }
898	
899	    ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
900	                  "client sent unknown pseudo-header \"%V\"", name);
901	
902	failed:
903	
904	    ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
905	    return NGX_ERROR;
906	}
