908	
909	static ngx_int_t
910	ngx_http_v3_init_pseudo_headers(ngx_http_request_t *r)
911	{
912	    size_t      len;
913	    u_char     *p;
914	    ngx_int_t   rc;
915	    ngx_str_t   host;
916	    in_port_t   port;
917	
918	    if (r->request_line.len) {
919	        return NGX_OK;
920	    }
921	
922	    if (r->method_name.len == 0) {
923	        ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
924	                      "client sent no \":method\" header");
925	        goto failed;
926	    }
927	
928	    if (r->schema.len == 0) {
929	        ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
930	                      "client sent no \":scheme\" header");
931	        goto failed;
932	    }
933	
934	    if (r->uri_start == NULL) {
935	        ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
936	                      "client sent no \":path\" header");
937	        goto failed;
938	    }
939	
940	    len = r->method_name.len + 1
941	          + (r->uri_end - r->uri_start) + 1
942	          + sizeof("HTTP/3.0") - 1;
943	
944	    p = ngx_pnalloc(r->pool, len);
945	    if (p == NULL) {
946	        ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
947	        return NGX_ERROR;
948	    }
949	
950	    r->request_line.data = p;
951	
952	    p = ngx_cpymem(p, r->method_name.data, r->method_name.len);
953	    *p++ = ' ';
954	    p = ngx_cpymem(p, r->uri_start, r->uri_end - r->uri_start);
955	    *p++ = ' ';
956	    p = ngx_cpymem(p, "HTTP/3.0", sizeof("HTTP/3.0") - 1);
957	
958	    r->request_line.len = p - r->request_line.data;
959	
960	    ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
961	                   "http3 request line: \"%V\"", &r->request_line);
962	
963	    ngx_str_set(&r->http_protocol, "HTTP/3.0");
964	
965	    if (ngx_http_process_request_uri(r) != NGX_OK) {
966	        return NGX_ERROR;
967	    }
968	
969	    if (r->host_end) {
970	
971	        host.len = r->host_end - r->host_start;
972	        host.data = r->host_start;
973	
974	        rc = ngx_http_validate_host(&host, &port, r->pool, 0);
975	
976	        if (rc == NGX_DECLINED) {
977	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
978	                          "client sent invalid \":authority\" header");
979	            goto failed;
980	        }
981	
982	        if (rc == NGX_ERROR) {
983	            ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
984	            return NGX_ERROR;
985	        }
986	
987	        if (ngx_http_set_virtual_server(r, &host) == NGX_ERROR) {
988	            return NGX_ERROR;
989	        }
990	
991	        r->headers_in.server = host;
992	        r->port = port;
993	    }
994	
995	    if (ngx_list_init(&r->headers_in.headers, r->pool, 20,
996	                      sizeof(ngx_table_elt_t))
997	        != NGX_OK)
998	    {
999	        ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
1000	        return NGX_ERROR;
1001	    }
1002	
1003	    return NGX_OK;
1004	
1005	failed:
1006	
1007	    ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
1008	    return NGX_ERROR;
1009	}
1010	
1011	
1012	static ngx_int_t
1013	ngx_http_v3_process_request_header(ngx_http_request_t *r)
1014	{
1015	    ssize_t                  n;
1016	    ngx_buf_t               *b;
1017	    ngx_str_t                host;
1018	    ngx_connection_t        *c;
1019	    ngx_http_v3_session_t   *h3c;
1020	    ngx_http_v3_srv_conf_t  *h3scf;
1021	
1022	    c = r->connection;
1023	
1024	    if (r->headers_in.connection) {
1025	        ngx_log_error(NGX_LOG_INFO, c->log, 0,
1026	                      "client sent \"Connection\" header");
1027	        ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
1028	        return NGX_ERROR;
1029	    }
1030	
1031	    if (r->headers_in.keep_alive) {
1032	        ngx_log_error(NGX_LOG_INFO, c->log, 0,
1033	                      "client sent \"Keep-Alive\" header");
1034	        ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
1035	        return NGX_ERROR;
1036	    }
1037	
1038	    if (r->headers_in.transfer_encoding) {
1039	        ngx_log_error(NGX_LOG_INFO, c->log, 0,
1040	                      "client sent \"Transfer-Encoding\" header");
1041	        ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
1042	        return NGX_ERROR;
1043	    }
1044	
1045	    if (r->headers_in.upgrade) {
1046	        ngx_log_error(NGX_LOG_INFO, c->log, 0,
1047	                      "client sent \"Upgrade\" header");
1048	        ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
1049	        return NGX_ERROR;
1050	    }
1051	
1052	    if (r->headers_in.te
1053	        && (r->headers_in.te->next
1054	            || r->headers_in.te->value.len != 8
1055	            || ngx_strncasecmp(r->headers_in.te->value.data,
1056	                               (u_char *) "trailers", 8) != 0))
1057	    {
1058	        ngx_log_error(NGX_LOG_INFO, c->log, 0,
1059	                      "client sent invalid \"TE\" header");
1060	        ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
1061	        return NGX_ERROR;
1062	    }
1063	
1064	    if (ngx_http_v3_init_pseudo_headers(r) != NGX_OK) {
1065	        return NGX_ERROR;
1066	    }
1067	
1068	    h3c = ngx_http_v3_get_session(c);
1069	    h3scf = ngx_http_get_module_srv_conf(r, ngx_http_v3_module);
1070	
1071	    if ((h3c->hq && !h3scf->enable_hq) || (!h3c->hq && !h3scf->enable)) {
1072	        ngx_log_error(NGX_LOG_INFO, c->log, 0,
1073	                      "client attempted to request the server name "
1074	                      "for which the negotiated protocol is disabled");
1075	        ngx_http_finalize_request(r, NGX_HTTP_MISDIRECTED_REQUEST);
1076	        return NGX_ERROR;
1077	    }
1078	
1079	    if (ngx_http_v3_construct_cookie_header(r) != NGX_OK) {
1080	        return NGX_ERROR;
1081	    }
1082	
1083	    if (r->headers_in.server.len == 0) {
1084	        ngx_log_error(NGX_LOG_INFO, c->log, 0,
1085	                      "client sent neither \":authority\" nor \"Host\" header");
1086	        goto failed;
1087	    }
1088	
1089	    if (r->headers_in.host && r->host_end) {
1090	
1091	        host.len = r->host_end - r->host_start;
1092	        host.data = r->host_start;
1093	
1094	        if (r->headers_in.host->value.len != host.len
1095	            || ngx_memcmp(r->headers_in.host->value.data, host.data, host.len)
1096	               != 0)
1097	        {
1098	            ngx_log_error(NGX_LOG_INFO, c->log, 0,
1099	                          "client sent \":authority\" and \"Host\" headers "
1100	                          "with different values");
1101	            goto failed;
1102	        }
1103	    }
1104	
1105	    if (r->headers_in.content_length) {
1106	        r->headers_in.content_length_n =
1107	                            ngx_atoof(r->headers_in.content_length->value.data,
1108	                                      r->headers_in.content_length->value.len);
1109	
1110	        if (r->headers_in.content_length_n == NGX_ERROR) {
1111	            ngx_log_error(NGX_LOG_INFO, c->log, 0,
1112	                          "client sent invalid \"Content-Length\" header");
1113	            goto failed;
1114	        }
1115	
1116	    } else {
1117	        b = r->header_in;
1118	        n = b->last - b->pos;
1119	
1120	        if (n == 0) {
1121	            n = c->recv(c, b->start, b->end - b->start);
1122	
1123	            if (n == NGX_ERROR) {
1124	                ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
1125	                return NGX_ERROR;
1126	            }
1127	
1128	            if (n > 0) {
1129	                b->pos = b->start;
1130	                b->last = b->start + n;
1131	            }
1132	        }
1133	
1134	        if (n != 0) {
1135	            r->headers_in.chunked = 1;
1136	        }
1137	    }
1138	
1139	    if (r->method == NGX_HTTP_CONNECT) {
1140	        ngx_log_error(NGX_LOG_INFO, c->log, 0, "client sent CONNECT method");
1141	        ngx_http_finalize_request(r, NGX_HTTP_NOT_ALLOWED);
1142	        return NGX_ERROR;
1143	    }
1144	
1145	    if (r->method == NGX_HTTP_TRACE) {
1146	        ngx_log_error(NGX_LOG_INFO, c->log, 0, "client sent TRACE method");
1147	        ngx_http_finalize_request(r, NGX_HTTP_NOT_ALLOWED);
1148	        return NGX_ERROR;
1149	    }
1150	
1151	    return NGX_OK;
1152	
1153	failed:
1154	
1155	    ngx_http_finalize_request(r, NGX_HTTP_BAD_REQUEST);
1156	    return NGX_ERROR;
1157	}
1158	
1159	
1160	static ngx_int_t
1161	ngx_http_v3_cookie(ngx_http_request_t *r, ngx_str_t *value)
1162	{
1163	    ngx_str_t    *val;
1164	    ngx_array_t  *cookies;
1165	
1166	    cookies = r->v3_parse->cookies;
1167	
1168	    if (cookies == NULL) {
1169	        cookies = ngx_array_create(r->pool, 2, sizeof(ngx_str_t));
1170	        if (cookies == NULL) {
1171	            return NGX_ERROR;
1172	        }
1173	
1174	        r->v3_parse->cookies = cookies;
1175	    }
1176	
1177	    val = ngx_array_push(cookies);
1178	    if (val == NULL) {
1179	        return NGX_ERROR;
1180	    }
1181	
1182	    *val = *value;
1183	
1184	    return NGX_OK;
1185	}
