1187	
1188	static ngx_int_t
1189	ngx_http_v3_construct_cookie_header(ngx_http_request_t *r)
1190	{
1191	    u_char                     *buf, *p, *end;
1192	    size_t                      len;
1193	    ngx_str_t                  *vals;
1194	    ngx_uint_t                  i;
1195	    ngx_array_t                *cookies;
1196	    ngx_table_elt_t            *h;
1197	    ngx_http_header_t          *hh;
1198	    ngx_http_core_main_conf_t  *cmcf;
1199	
1200	    static ngx_str_t cookie = ngx_string("cookie");
1201	
1202	    cookies = r->v3_parse->cookies;
1203	
1204	    if (cookies == NULL) {
1205	        return NGX_OK;
1206	    }
1207	
1208	    vals = cookies->elts;
1209	
1210	    i = 0;
1211	    len = 0;
1212	
1213	    do {
1214	        len += vals[i].len + 2;
1215	    } while (++i != cookies->nelts);
1216	
1217	    len -= 2;
1218	
1219	    buf = ngx_pnalloc(r->pool, len + 1);
1220	    if (buf == NULL) {
1221	        ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
1222	        return NGX_ERROR;
1223	    }
1224	
1225	    p = buf;
1226	    end = buf + len;
1227	
1228	    for (i = 0; /* void */ ; i++) {
1229	
1230	        p = ngx_cpymem(p, vals[i].data, vals[i].len);
1231	
1232	        if (p == end) {
1233	            *p = '\0';
1234	            break;
1235	        }
1236	
1237	        *p++ = ';'; *p++ = ' ';
1238	    }
1239	
1240	    h = ngx_list_push(&r->headers_in.headers);
1241	    if (h == NULL) {
1242	        ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
1243	        return NGX_ERROR;
1244	    }
1245	
1246	    h->hash = ngx_hash(ngx_hash(ngx_hash(ngx_hash(
1247	                                    ngx_hash('c', 'o'), 'o'), 'k'), 'i'), 'e');
1248	
1249	    h->key.len = cookie.len;
1250	    h->key.data = cookie.data;
1251	
1252	    h->value.len = len;
1253	    h->value.data = buf;
1254	
1255	    h->lowcase_key = cookie.data;
1256	
1257	    cmcf = ngx_http_get_module_main_conf(r, ngx_http_core_module);
1258	
1259	    hh = ngx_hash_find(&cmcf->headers_in_hash, h->hash,
1260	                       h->lowcase_key, h->key.len);
1261	
1262	    if (hh == NULL) {
1263	        ngx_http_close_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
1264	        return NGX_ERROR;
1265	    }
1266	
1267	    if (hh->handler(r, h, hh->offset) != NGX_OK) {
1268	        /*
1269	         * request has been finalized already
1270	         * in ngx_http_process_header_line()
1271	         */
1272	        return NGX_ERROR;
1273	    }
1274	
1275	    return NGX_OK;
1276	}
