1278	
1279	ngx_int_t
1280	ngx_http_v3_read_request_body(ngx_http_request_t *r)
1281	{
1282	    size_t                     preread;
1283	    ngx_int_t                  rc;
1284	    ngx_chain_t               *cl, out;
1285	    ngx_http_request_body_t   *rb;
1286	    ngx_http_core_loc_conf_t  *clcf;
1287	
1288	    rb = r->request_body;
1289	
1290	    preread = r->header_in->last - r->header_in->pos;
1291	
1292	    if (preread) {
1293	
1294	        /* there is the pre-read part of the request body */
1295	
1296	        ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
1297	                       "http3 client request body preread %uz", preread);
1298	
1299	        out.buf = r->header_in;
1300	        out.next = NULL;
1301	        cl = &out;
1302	
1303	    } else {
1304	        cl = NULL;
1305	    }
1306	
1307	    rc = ngx_http_v3_request_body_filter(r, cl);
1308	    if (rc != NGX_OK) {
1309	        return rc;
1310	    }
1311	
1312	    if (rb->rest == 0 && rb->last_saved) {
1313	        /* the whole request body was pre-read */
1314	        r->request_body_no_buffering = 0;
1315	        rb->post_handler(r);
1316	        return NGX_OK;
1317	    }
1318	
1319	    if (rb->rest < 0) {
1320	        ngx_log_error(NGX_LOG_ALERT, r->connection->log, 0,
1321	                      "negative request body rest");
1322	        return NGX_HTTP_INTERNAL_SERVER_ERROR;
1323	    }
1324	
1325	    clcf = ngx_http_get_module_loc_conf(r, ngx_http_core_module);
1326	
1327	    rb->buf = ngx_create_temp_buf(r->pool, clcf->client_body_buffer_size);
1328	    if (rb->buf == NULL) {
1329	        return NGX_HTTP_INTERNAL_SERVER_ERROR;
1330	    }
1331	
1332	    r->read_event_handler = ngx_http_v3_read_client_request_body_handler;
1333	    r->write_event_handler = ngx_http_request_empty_handler;
1334	
1335	    return ngx_http_v3_do_read_client_request_body(r);
1336	}
