1339	static void
1340	ngx_http_v3_read_client_request_body_handler(ngx_http_request_t *r)
1341	{
1342	    ngx_int_t  rc;
1343	
1344	    if (r->connection->read->timedout) {
1345	        r->connection->timedout = 1;
1346	        ngx_http_finalize_request(r, NGX_HTTP_REQUEST_TIME_OUT);
1347	        return;
1348	    }
1349	
1350	    rc = ngx_http_v3_do_read_client_request_body(r);
1351	
1352	    if (rc >= NGX_HTTP_SPECIAL_RESPONSE) {
1353	        ngx_http_finalize_request(r, rc);
1354	    }
1355	}
