1358	ngx_int_t
1359	ngx_http_v3_read_unbuffered_request_body(ngx_http_request_t *r)
1360	{
1361	    ngx_int_t  rc;
1362	
1363	    if (r->connection->read->timedout) {
1364	        r->connection->timedout = 1;
1365	        return NGX_HTTP_REQUEST_TIME_OUT;
1366	    }
1367	
1368	    rc = ngx_http_v3_do_read_client_request_body(r);
1369	
1370	    if (rc == NGX_OK) {
1371	        r->reading_body = 0;
1372	    }
1373	
1374	    return rc;
1375	}
