1377	
1378	static ngx_int_t
1379	ngx_http_v3_do_read_client_request_body(ngx_http_request_t *r)
1380	{
1381	    off_t                      rest;
1382	    size_t                     size;
1383	    ssize_t                    n;
1384	    ngx_int_t                  rc;
1385	    ngx_uint_t                 flush;
1386	    ngx_chain_t                out;
1387	    ngx_connection_t          *c;
1388	    ngx_http_request_body_t   *rb;
1389	    ngx_http_core_loc_conf_t  *clcf;
1390	
1391	    c = r->connection;
1392	    rb = r->request_body;
1393	    flush = 1;
1394	
1395	    ngx_log_debug0(NGX_LOG_DEBUG_HTTP, c->log, 0,
1396	                   "http3 read client request body");
1397	
1398	    for ( ;; ) {
1399	        for ( ;; ) {
1400	            if (rb->rest == 0) {
1401	                break;
1402	            }
1403	
1404	            if (rb->buf->last == rb->buf->end) {
1405	
1406	                /* update chains */
1407	
1408	                rc = ngx_http_v3_request_body_filter(r, NULL);
1409	
1410	                if (rc != NGX_OK) {
1411	                    return rc;
1412	                }
1413	
1414	                if (rb->busy != NULL) {
1415	                    if (r->request_body_no_buffering) {
1416	                        if (c->read->timer_set) {
1417	                            ngx_del_timer(c->read);
1418	                        }
1419	
1420	                        if (ngx_handle_read_event(c->read, 0) != NGX_OK) {
1421	                            return NGX_HTTP_INTERNAL_SERVER_ERROR;
1422	                        }
1423	
1424	                        return NGX_AGAIN;
1425	                    }
1426	
1427	                    if (rb->filter_need_buffering) {
1428	                        clcf = ngx_http_get_module_loc_conf(r,
1429	                                                         ngx_http_core_module);
1430	                        ngx_add_timer(c->read, clcf->client_body_timeout);
1431	
1432	                        if (ngx_handle_read_event(c->read, 0) != NGX_OK) {
1433	                            return NGX_HTTP_INTERNAL_SERVER_ERROR;
1434	                        }
1435	
1436	                        return NGX_AGAIN;
1437	                    }
1438	
1439	                    ngx_log_error(NGX_LOG_ALERT, c->log, 0,
1440	                                  "busy buffers after request body flush");
1441	
1442	                    return NGX_HTTP_INTERNAL_SERVER_ERROR;
1443	                }
1444	
1445	                flush = 0;
1446	                rb->buf->pos = rb->buf->start;
1447	                rb->buf->last = rb->buf->start;
1448	            }
1449	
1450	            size = rb->buf->end - rb->buf->last;
1451	            rest = rb->rest - (rb->buf->last - rb->buf->pos);
1452	
1453	            if ((off_t) size > rest) {
1454	                size = (size_t) rest;
1455	            }
1456	
1457	            if (size == 0) {
1458	                break;
1459	            }
1460	
1461	            n = c->recv(c, rb->buf->last, size);
1462	
1463	            ngx_log_debug1(NGX_LOG_DEBUG_HTTP, c->log, 0,
1464	                           "http3 client request body recv %z", n);
1465	
1466	            if (n == NGX_AGAIN) {
1467	                break;
1468	            }
1469	
1470	            if (n == 0) {
1471	                rb->buf->last_buf = 1;
1472	            }
1473	
1474	            if (n == NGX_ERROR) {
1475	                c->error = 1;
1476	                return NGX_HTTP_BAD_REQUEST;
1477	            }
1478	
1479	            rb->buf->last += n;
1480	
1481	            /* pass buffer to request body filter chain */
1482	
1483	            flush = 0;
1484	            out.buf = rb->buf;
1485	            out.next = NULL;
1486	
1487	            rc = ngx_http_v3_request_body_filter(r, &out);
1488	
1489	            if (rc != NGX_OK) {
1490	                return rc;
1491	            }
1492	
1493	            if (rb->rest == 0) {
1494	                break;
1495	            }
1496	
1497	            if (rb->buf->last < rb->buf->end) {
1498	                break;
1499	            }
1500	        }
1501	
1502	        ngx_log_debug1(NGX_LOG_DEBUG_HTTP, c->log, 0,
1503	                       "http3 client request body rest %O", rb->rest);
1504	
1505	        if (flush) {
1506	            rc = ngx_http_v3_request_body_filter(r, NULL);
1507	
1508	            if (rc != NGX_OK) {
1509	                return rc;
1510	            }
1511	        }
1512	
1513	        if (rb->rest == 0 && rb->last_saved) {
1514	            break;
1515	        }
1516	
1517	        if (!c->read->ready || rb->rest == 0) {
1518	
1519	            clcf = ngx_http_get_module_loc_conf(r, ngx_http_core_module);
1520	            ngx_add_timer(c->read, clcf->client_body_timeout);
1521	
1522	            if (ngx_handle_read_event(c->read, 0) != NGX_OK) {
1523	                return NGX_HTTP_INTERNAL_SERVER_ERROR;
1524	            }
1525	
1526	            return NGX_AGAIN;
1527	        }
1528	    }
1529	
1530	    if (c->read->timer_set) {
1531	        ngx_del_timer(c->read);
1532	    }
1533	
1534	    if (!r->request_body_no_buffering) {
1535	        r->read_event_handler = ngx_http_block_reading;
1536	        rb->post_handler(r);
1537	    }
1538	
1539	    return NGX_OK;
1540	}
