1542	
1543	static ngx_int_t
1544	ngx_http_v3_request_body_filter(ngx_http_request_t *r, ngx_chain_t *in)
1545	{
1546	    off_t                      max;
1547	    size_t                     size;
1548	    u_char                    *p;
1549	    ngx_int_t                  rc;
1550	    ngx_buf_t                 *b;
1551	    ngx_uint_t                 last;
1552	    ngx_chain_t               *cl, *out, *tl, **ll;
1553	    ngx_http_v3_session_t     *h3c;
1554	    ngx_http_request_body_t   *rb;
1555	    ngx_http_core_loc_conf_t  *clcf;
1556	    ngx_http_core_srv_conf_t  *cscf;
1557	    ngx_http_v3_parse_data_t  *st;
1558	
1559	    rb = r->request_body;
1560	    st = &r->v3_parse->body;
1561	
1562	    h3c = ngx_http_v3_get_session(r->connection);
1563	
1564	    if (rb->rest == -1) {
1565	
1566	        ngx_log_debug0(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
1567	                       "http3 request body filter");
1568	
1569	        cscf = ngx_http_get_module_srv_conf(r, ngx_http_core_module);
1570	
1571	        rb->rest = cscf->large_client_header_buffers.size;
1572	    }
1573	
1574	    clcf = ngx_http_get_module_loc_conf(r, ngx_http_core_module);
1575	
1576	    max = r->headers_in.content_length_n;
1577	
1578	    if (max == -1 && clcf->client_max_body_size) {
1579	        max = clcf->client_max_body_size;
1580	    }
1581	
1582	    out = NULL;
1583	    ll = &out;
1584	    last = 0;
1585	
1586	    for (cl = in; cl; cl = cl->next) {
1587	
1588	        ngx_log_debug7(NGX_LOG_DEBUG_EVENT, r->connection->log, 0,
1589	                       "http3 body buf "
1590	                       "t:%d f:%d %p, pos %p, size: %z file: %O, size: %O",
1591	                       cl->buf->temporary, cl->buf->in_file,
1592	                       cl->buf->start, cl->buf->pos,
1593	                       cl->buf->last - cl->buf->pos,
1594	                       cl->buf->file_pos,
1595	                       cl->buf->file_last - cl->buf->file_pos);
1596	
1597	        if (cl->buf->last_buf) {
1598	            last = 1;
1599	        }
1600	
1601	        b = NULL;
1602	
1603	        while (cl->buf->pos < cl->buf->last) {
1604	
1605	            if (st->length == 0) {
1606	                p = cl->buf->pos;
1607	
1608	                rc = ngx_http_v3_parse_data(r->connection, st, cl->buf);
1609	
1610	                r->request_length += cl->buf->pos - p;
1611	                h3c->total_bytes += cl->buf->pos - p;
1612	
1613	                if (ngx_http_v3_check_flood(r->connection) != NGX_OK) {
1614	                    return NGX_HTTP_CLOSE;
1615	                }
1616	
1617	                if (rc == NGX_AGAIN) {
1618	                    continue;
1619	                }
1620	
1621	                if (rc == NGX_DONE) {
1622	                    last = 1;
1623	                    goto done;
1624	                }
1625	
1626	                if (rc > 0) {
1627	                    ngx_quic_reset_stream(r->connection, rc);
1628	                    ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
1629	                                  "client sent invalid body");
1630	                    return NGX_HTTP_BAD_REQUEST;
1631	                }
1632	
1633	                if (rc == NGX_ERROR) {
1634	                    return NGX_HTTP_INTERNAL_SERVER_ERROR;
1635	                }
1636	
1637	                /* rc == NGX_OK */
1638	
1639	                if (max != -1 && (uint64_t) (max - rb->received) < st->length) {
1640	
1641	                    if (r->headers_in.content_length_n != -1) {
1642	                        ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
1643	                                      "client intended to send body data "
1644	                                      "larger than declared");
1645	
1646	                        return NGX_HTTP_BAD_REQUEST;
1647	                    }
1648	
1649	                    ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
1650	                                  "client intended to send too large "
1651	                                  "body: %O+%ui bytes",
1652	                                  rb->received, st->length);
1653	
1654	                    return NGX_HTTP_REQUEST_ENTITY_TOO_LARGE;
1655	                }
1656	
1657	                continue;
1658	            }
1659	
1660	            if (b
1661	                && st->length <= 128
1662	                && (uint64_t) (cl->buf->last - cl->buf->pos) >= st->length)
1663	            {
1664	                rb->received += st->length;
1665	                r->request_length += st->length;
1666	                h3c->total_bytes += st->length;
1667	                h3c->payload_bytes += st->length;
1668	
1669	                if (st->length < 8) {
1670	
1671	                    while (st->length) {
1672	                        *b->last++ = *cl->buf->pos++;
1673	                        st->length--;
1674	                    }
1675	
1676	                } else {
1677	                    ngx_memmove(b->last, cl->buf->pos, st->length);
1678	                    b->last += st->length;
1679	                    cl->buf->pos += st->length;
1680	                    st->length = 0;
1681	                }
1682	
1683	                continue;
1684	            }
1685	
1686	            tl = ngx_chain_get_free_buf(r->pool, &rb->free);
1687	            if (tl == NULL) {
1688	                return NGX_HTTP_INTERNAL_SERVER_ERROR;
1689	            }
1690	
1691	            b = tl->buf;
1692	
1693	            ngx_memzero(b, sizeof(ngx_buf_t));
1694	
1695	            b->temporary = 1;
1696	            b->tag = (ngx_buf_tag_t) &ngx_http_read_client_request_body;
1697	            b->start = cl->buf->pos;
1698	            b->pos = cl->buf->pos;
1699	            b->last = cl->buf->last;
1700	            b->end = cl->buf->end;
1701	            b->flush = r->request_body_no_buffering;
1702	
1703	            *ll = tl;
1704	            ll = &tl->next;
1705	
1706	            size = cl->buf->last - cl->buf->pos;
1707	
1708	            if (size > st->length) {
1709	                cl->buf->pos += (size_t) st->length;
1710	                rb->received += st->length;
1711	                r->request_length += st->length;
1712	                h3c->total_bytes += st->length;
1713	                h3c->payload_bytes += st->length;
1714	                st->length = 0;
1715	
1716	            } else {
1717	                st->length -= size;
1718	                rb->received += size;
1719	                r->request_length += size;
1720	                h3c->total_bytes += size;
1721	                h3c->payload_bytes += size;
1722	                cl->buf->pos = cl->buf->last;
1723	            }
1724	
1725	            b->last = cl->buf->pos;
1726	        }
1727	    }
1728	
1729	done:
1730	
1731	    if (last) {
1732	
1733	        if (st->length > 0) {
1734	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
1735	                          "client prematurely closed stream");
1736	            r->connection->error = 1;
1737	            return NGX_HTTP_BAD_REQUEST;
1738	        }
1739	
1740	        if (r->headers_in.content_length_n == -1) {
1741	            r->headers_in.content_length_n = rb->received;
1742	
1743	        } else if (r->headers_in.content_length_n != rb->received) {
1744	            ngx_log_error(NGX_LOG_INFO, r->connection->log, 0,
1745	                          "client sent less body data than expected: "
1746	                          "%O out of %O bytes of request body received",
1747	                          rb->received, r->headers_in.content_length_n);
1748	            return NGX_HTTP_BAD_REQUEST;
1749	        }
1750	
1751	        rb->rest = 0;
1752	
1753	        tl = ngx_chain_get_free_buf(r->pool, &rb->free);
1754	        if (tl == NULL) {
1755	            return NGX_HTTP_INTERNAL_SERVER_ERROR;
1756	        }
1757	
1758	        b = tl->buf;
1759	
1760	        ngx_memzero(b, sizeof(ngx_buf_t));
1761	
1762	        b->last_buf = 1;
1763	
1764	        *ll = tl;
1765	
1766	    } else {
1767	
1768	        /* set rb->rest, amount of data we want to see next time */
1769	
1770	        cscf = ngx_http_get_module_srv_conf(r, ngx_http_core_module);
1771	
1772	        rb->rest = (off_t) cscf->large_client_header_buffers.size;
1773	    }
1774	
1775	    rc = ngx_http_top_request_body_filter(r, out);
1776	
1777	    ngx_chain_update_chains(r->pool, &rb->free, &rb->busy, &out,
1778	                            (ngx_buf_tag_t) &ngx_http_read_client_request_body);
1779	
1780	    return rc;
1781	}
